#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

int main()
{
	int a,b,c;
	cin>>a>>b>>c;
	if(a<b) swap(a,b);
	if(a<c) swap(a,c);
	if(b+c>a){
		if(b*b+c*c==a*a){
			cout<<"Right triangle" <<endl;
		 }
		if(b*b+c*c>a*a){
			cout<<"Acute triangle"<<endl;
		}
		if(b*b+c*c<a*a){
			cout<<"Obtuse triangle" <<endl;
		}
		if(b==c){
			cout<<"Isosceles triangle" <<endl;
		}
		if(a==b&&b==c){
			cout<<"Equilateral triangle"<<endl ;
		} 
	} 
	else cout<<"Not triangle";	
	return 0;
}
